/* eslint-disable camelcase */
import {
  VitessceConfig,
  CoordinationLevel as CL,
  hconcat,
  vconcat,
  getInitialCoordinationScopePrefix,
} from '@vitessce/config';

// Configs for spatialdata blobs fixtures generated by
// create-fixtures.py, converted to JSON, and
// copied into examples/configs/src/json-fixtures/sdata-blobs directory.
// The JSON configs are directly imported into examples/configs/src/index.js.

function generateBlobsConfig_0_3() {
  const config = new VitessceConfig({
    schemaVersion: '1.0.18',
    name: 'SpatialData blobs toy dataset, generated with v0.3.x of the spatialdata Python package',
  });
  const dataset = config.addDataset('Blobs').addFile({
    fileType: 'spatialdata.zarr',
    url: 'blobs.sdata.zarr',
    options: {
      image: {
        path: 'images/blobs_multiscale_image',
      },
      obsFeatureMatrix: {
        path: 'tables/table/X',
      },
      obsSegmentations: {
        path: 'labels/blobs_labels',
      },
      obsSets: {
        tablePath: 'tables/table',
        obsSets: [
          {
            name: 'Region',
            path: 'tables/table/obs/region',
          },
        ],
      },
    },
    coordinationValues: {
      obsType: 'blob',
      featureType: 'channel',
      fileUid: 'my_unique_id',
    },
  }).addFile({
    fileType: 'spatialdata.zarr',
    url: 'blobs.sdata.zarr',
    options: {
      obsPoints: {
        path: 'points/blobs_points',
      },
      obsFeatureMatrix: {
        path: 'tables/table_points/X',
      },
    },
    coordinationValues: {
      obsType: 'point',
      featureType: 'gene',
      fileUid: 'other_unique_id',
    },
  });

  const spatialView = config.addView(dataset, 'spatialBeta');
  const lcView = config.addView(dataset, 'layerControllerBeta');
  const obsSets = config.addView(dataset, 'obsSets');
  const channelList = config.addView(dataset, 'featureList');
  const geneList = config.addView(dataset, 'featureList');

  config.linkViewsByObject([spatialView, lcView], {
    imageLayer: CL({
      fileUid: 'my_unique_id',
    }),
  }, { scopePrefix: getInitialCoordinationScopePrefix('A', 'image') });

  config.linkViewsByObject([spatialView, lcView], {
    segmentationLayer: CL([{
      fileUid: 'my_unique_id',
      segmentationChannel: CL([
        {
          obsType: 'blob',
          featureType: 'channel',
        },
      ]),
    }]),
  }, { scopePrefix: getInitialCoordinationScopePrefix('A', 'obsSegmentations') });

  config.linkViewsByObject([spatialView, lcView], {
    pointLayer: CL({
      fileUid: 'other_unique_id',
      obsType: 'point',
      featureType: 'gene',
    }),
  }, { scopePrefix: getInitialCoordinationScopePrefix('A', 'obsPoints') });

  config.linkViewsByObject([channelList], {
    obsType: 'blob',
    featureType: 'channel',
  });
  config.linkViewsByObject([obsSets], {
    obsType: 'blob',
  });
  config.linkViewsByObject([geneList], {
    obsType: 'point',
    featureType: 'gene',
  });

  config.layout(hconcat(spatialView, vconcat(lcView, hconcat(channelList, geneList), obsSets)));

  const configJSON = config.toJSON();
  return configJSON;
}


export const spatialdataBlobsFixtureConfig_0_3 = generateBlobsConfig_0_3();
export const spatialdataBlobsFixtureConfig_0_7 = generateBlobsConfig_0_3();
